import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.6MCaaFDc.js";const p=JSON.parse('{"title":"Cloud Computing & Virtualisation","description":"","frontmatter":{},"headers":[],"relativePath":"theory/systems/cloud-virtualisation.md","filePath":"theory/systems/cloud-virtualisation.md"}'),s={name:"theory/systems/cloud-virtualisation.md"};function d(n,t,i,l,u,c){return a(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="cloud-computing-virtualisation" tabindex="-1">Cloud Computing &amp; Virtualisation <a class="header-anchor" href="#cloud-computing-virtualisation" aria-label="Permalink to &quot;Cloud Computing &amp; Virtualisation&quot;">​</a></h1><p>Your files are on your phone, your laptop, and accessible from any computer in the world — that&#39;s the cloud. Behind the scenes, physical servers run dozens of virtual machines simultaneously. These two technologies — cloud and virtualisation — have reshaped how businesses and individuals use computing.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11–12</p><p>Cloud computing is introduced at Grade 11. Virtualisation and deeper cloud architecture are Grade 12 content.</p></div><hr><h2 id="what-is-cloud-computing" tabindex="-1">What is Cloud Computing? <a class="header-anchor" href="#what-is-cloud-computing" aria-label="Permalink to &quot;What is Cloud Computing?&quot;">​</a></h2><p><strong>Cloud computing</strong> is the delivery of computing services (servers, storage, software, databases, networking) over the internet (&quot;the cloud&quot;), provided by a third-party company.</p><p>Instead of owning hardware and software, you pay to use resources hosted elsewhere.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Traditional model: Buy server → Install software → Maintain it yourself</span></span>
<span class="line"><span>Cloud model:       Connect to internet → Access service → Pay for what you use</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="cloud-service-models" tabindex="-1">Cloud Service Models <a class="header-anchor" href="#cloud-service-models" aria-label="Permalink to &quot;Cloud Service Models&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Model</th><th>Full Name</th><th>What you get</th><th>You manage</th><th>Examples</th></tr></thead><tbody><tr><td><strong>IaaS</strong></td><td>Infrastructure as a Service</td><td>Virtual hardware (CPU, storage, networking)</td><td>OS, apps, data</td><td>AWS EC2, Microsoft Azure, Google Cloud</td></tr><tr><td><strong>PaaS</strong></td><td>Platform as a Service</td><td>Development environment + runtime</td><td>Apps and data</td><td>Google App Engine, Heroku</td></tr><tr><td><strong>SaaS</strong></td><td>Software as a Service</td><td>Ready-to-use software via browser</td><td>Only your data</td><td>Gmail, Microsoft 365, Netflix, Dropbox</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Memory Aid</p><p>Think of it as a pizza analogy:</p><ul><li><strong>IaaS</strong> = you get a kitchen (you cook everything)</li><li><strong>PaaS</strong> = you get pizza dough (you add toppings)</li><li><strong>SaaS</strong> = you get a delivered pizza (just eat it)</li></ul></div><hr><h2 id="cloud-deployment-models" tabindex="-1">Cloud Deployment Models <a class="header-anchor" href="#cloud-deployment-models" aria-label="Permalink to &quot;Cloud Deployment Models&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Model</th><th>Who uses it</th><th>Description</th></tr></thead><tbody><tr><td><strong>Public cloud</strong></td><td>Anyone</td><td>Shared infrastructure owned by provider (AWS, Azure, Google)</td></tr><tr><td><strong>Private cloud</strong></td><td>One organisation</td><td>Dedicated infrastructure, greater control, higher cost</td></tr><tr><td><strong>Hybrid cloud</strong></td><td>Mixed</td><td>Combination of public and private — sensitive data on private, other services on public</td></tr><tr><td><strong>Community cloud</strong></td><td>Shared organisations</td><td>Shared by organisations with similar needs (e.g. government departments)</td></tr></tbody></table><hr><h2 id="advantages-of-cloud-computing" tabindex="-1">Advantages of Cloud Computing <a class="header-anchor" href="#advantages-of-cloud-computing" aria-label="Permalink to &quot;Advantages of Cloud Computing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Advantage</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Accessibility</strong></td><td>Access files and apps from any device, anywhere with internet</td></tr><tr><td><strong>Automatic backups</strong></td><td>Data backed up automatically by the provider</td></tr><tr><td><strong>Scalability</strong></td><td>Scale resources up or down as needed — no upfront hardware purchase</td></tr><tr><td><strong>Cost savings</strong></td><td>No capital expense on hardware; pay-as-you-go model</td></tr><tr><td><strong>Automatic updates</strong></td><td>Software updates handled by provider — always latest version</td></tr><tr><td><strong>Collaboration</strong></td><td>Multiple users can work on the same document simultaneously</td></tr><tr><td><strong>Disaster recovery</strong></td><td>Data survives local hardware failure</td></tr></tbody></table><hr><h2 id="disadvantages-of-cloud-computing" tabindex="-1">Disadvantages of Cloud Computing <a class="header-anchor" href="#disadvantages-of-cloud-computing" aria-label="Permalink to &quot;Disadvantages of Cloud Computing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Disadvantage</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Internet dependency</strong></td><td>No internet = no access to cloud services</td></tr><tr><td><strong>Privacy and security</strong></td><td>Data stored on third-party servers — risk of breach</td></tr><tr><td><strong>Ongoing cost</strong></td><td>Subscription costs accumulate over time — may exceed owning hardware</td></tr><tr><td><strong>Vendor lock-in</strong></td><td>Difficult to switch providers once data is stored in one ecosystem</td></tr><tr><td><strong>Limited control</strong></td><td>Cannot customise the underlying infrastructure</td></tr><tr><td><strong>Latency</strong></td><td>Network delays may slow access to data vs local storage</td></tr><tr><td><strong>Compliance concerns</strong></td><td>Data stored in other countries may face different legal jurisdictions</td></tr></tbody></table><hr><h2 id="cloud-storage-vs-local-storage" tabindex="-1">Cloud Storage vs Local Storage <a class="header-anchor" href="#cloud-storage-vs-local-storage" aria-label="Permalink to &quot;Cloud Storage vs Local Storage&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Cloud Storage</th><th>Local Storage (HDD/SSD)</th></tr></thead><tbody><tr><td>Access</td><td>Anywhere with internet</td><td>Only at that device</td></tr><tr><td>Backup</td><td>Automatic</td><td>Manual</td></tr><tr><td>Cost</td><td>Ongoing subscription</td><td>Once-off purchase</td></tr><tr><td>Speed</td><td>Limited by internet</td><td>Fast (local bus speed)</td></tr><tr><td>Privacy</td><td>Third-party holds data</td><td>Full control</td></tr><tr><td>Capacity</td><td>Scalable</td><td>Fixed</td></tr><tr><td>Risk</td><td>Provider outage</td><td>Drive failure</td></tr></tbody></table><hr><h2 id="popular-cloud-services" tabindex="-1">Popular Cloud Services <a class="header-anchor" href="#popular-cloud-services" aria-label="Permalink to &quot;Popular Cloud Services&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Provider</th><th>Category</th></tr></thead><tbody><tr><td>Google Drive</td><td>Google</td><td>Storage + SaaS</td></tr><tr><td>Microsoft OneDrive</td><td>Microsoft</td><td>Storage + SaaS</td></tr><tr><td>iCloud</td><td>Apple</td><td>Storage + SaaS</td></tr><tr><td>Dropbox</td><td>Dropbox</td><td>Storage</td></tr><tr><td>AWS</td><td>Amazon</td><td>IaaS + PaaS</td></tr><tr><td>Microsoft Azure</td><td>Microsoft</td><td>IaaS + PaaS + SaaS</td></tr><tr><td>Google Workspace</td><td>Google</td><td>SaaS</td></tr><tr><td>Microsoft 365</td><td>Microsoft</td><td>SaaS</td></tr><tr><td>Netflix</td><td>Netflix</td><td>SaaS (streaming)</td></tr></tbody></table><hr><h2 id="virtualisation" tabindex="-1">Virtualisation <a class="header-anchor" href="#virtualisation" aria-label="Permalink to &quot;Virtualisation&quot;">​</a></h2><p><strong>Virtualisation</strong> is the process of creating a virtual (software-based) version of a physical resource — such as a server, storage device, or operating system.</p><p>A single physical computer can run multiple <strong>virtual machines (VMs)</strong> simultaneously, each with its own OS and applications.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Physical Server (1 machine)</span></span>
<span class="line"><span>├── Virtual Machine 1 — Windows Server 2022</span></span>
<span class="line"><span>├── Virtual Machine 2 — Ubuntu Linux</span></span>
<span class="line"><span>└── Virtual Machine 3 — Windows 10</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="hypervisors" tabindex="-1">Hypervisors <a class="header-anchor" href="#hypervisors" aria-label="Permalink to &quot;Hypervisors&quot;">​</a></h2><p>A <strong>hypervisor</strong> (Virtual Machine Monitor) is software that manages and runs virtual machines on a host computer.</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Type 1 (Bare-metal)</strong></td><td>Runs directly on hardware — no host OS</td><td>VMware ESXi, Microsoft Hyper-V, Xen</td></tr><tr><td><strong>Type 2 (Hosted)</strong></td><td>Runs on top of an existing OS</td><td>VirtualBox, VMware Workstation, Parallels</td></tr></tbody></table><p><strong>Type 1</strong> is faster and used in enterprise data centres.<br><strong>Type 2</strong> is used on personal computers for testing and development.</p><hr><h2 id="benefits-of-virtualisation" tabindex="-1">Benefits of Virtualisation <a class="header-anchor" href="#benefits-of-virtualisation" aria-label="Permalink to &quot;Benefits of Virtualisation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benefit</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Better hardware utilisation</strong></td><td>One server running many VMs = less wasted capacity</td></tr><tr><td><strong>Cost reduction</strong></td><td>Fewer physical servers needed → lower hardware and energy costs</td></tr><tr><td><strong>Isolation</strong></td><td>If one VM crashes, others are unaffected</td></tr><tr><td><strong>Snapshots</strong></td><td>Save the state of a VM at a point in time — restore instantly if needed</td></tr><tr><td><strong>Portability</strong></td><td>VMs can be moved between physical hosts</td></tr><tr><td><strong>Quick provisioning</strong></td><td>Spin up a new server in minutes — no hardware ordering needed</td></tr><tr><td><strong>Testing environments</strong></td><td>Test software on different OS versions without multiple physical machines</td></tr></tbody></table><hr><h2 id="cloud-and-virtualisation-together" tabindex="-1">Cloud and Virtualisation Together <a class="header-anchor" href="#cloud-and-virtualisation-together" aria-label="Permalink to &quot;Cloud and Virtualisation Together&quot;">​</a></h2><p>Most cloud services are built on virtualisation:</p><ul><li>AWS, Azure, and Google Cloud all use hypervisors to create thousands of VMs</li><li>When you launch a cloud server, you&#39;re starting a VM on their physical hardware</li><li>This allows cloud providers to sell &quot;virtual servers&quot; to many customers on the same physical machine</li></ul><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Cloud computing</strong></td><td>Delivery of computing services over the internet</td></tr><tr><td><strong>IaaS</strong></td><td>Cloud model providing virtual hardware</td></tr><tr><td><strong>PaaS</strong></td><td>Cloud model providing development platform</td></tr><tr><td><strong>SaaS</strong></td><td>Cloud model providing ready-to-use software</td></tr><tr><td><strong>Virtualisation</strong></td><td>Creating software-based versions of physical resources</td></tr><tr><td><strong>Virtual machine (VM)</strong></td><td>Software-based computer running on a physical host</td></tr><tr><td><strong>Hypervisor</strong></td><td>Software that creates and manages virtual machines</td></tr><tr><td><strong>Snapshot</strong></td><td>Saved state of a virtual machine at a point in time</td></tr><tr><td><strong>Scalability</strong></td><td>Ability to increase or decrease resources on demand</td></tr><tr><td><strong>Vendor lock-in</strong></td><td>Difficulty of switching from one cloud provider to another</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Explain the difference between IaaS, PaaS, and SaaS. Give ONE example of each.&quot;</strong> — IaaS: virtual hardware (AWS); PaaS: dev platform (Heroku); SaaS: software via browser (Gmail, Microsoft 365)</p></li><li><p><strong>&quot;Give THREE advantages of cloud computing&quot;</strong> — accessibility from anywhere, automatic backups, scalability, cost savings, automatic updates — always explain each</p></li><li><p><strong>&quot;Give TWO disadvantages of cloud computing&quot;</strong> — internet dependency (no internet = no access); privacy concerns (data stored on third-party servers); ongoing subscription cost; vendor lock-in</p></li><li><p><strong>&quot;What is virtualisation? How does it benefit a business?&quot;</strong> — creating software-based versions of resources; benefits: better utilisation of hardware, cost reduction, isolation between VMs, snapshots for recovery</p></li><li><p><strong>&quot;Explain the difference between Type 1 and Type 2 hypervisors&quot;</strong> — Type 1 runs directly on hardware (enterprise use, faster); Type 2 runs on host OS (personal computers, VirtualBox)</p></li></ol></div>`,50)])])}const g=e(s,[["render",d]]);export{p as __pageData,g as default};
